def unique_digits(x):
    """Given a list of positive integers x. return a sorted list of all 
    elements that hasn't any even digit.

    Note: Returned list should be sorted in increasing order.

    For example:
    >>> unique_digits([15, 33, 1422, 1])
    [1, 15, 33]
    >>> unique_digits([152, 323, 1422, 10])
    []
    """
    def has_no_even_digit(n):
        return all(int(d) % 2 != 0 for d in str(n))

    return sorted([n for n in x if has_no_even_digit(n)])

def by_length(arr):
    names = {
        1: "One", 2: "Two", 3: "Three", 4: "Four", 5: "Five",
        6: "Six", 7: "Seven", 8: "Eight", 9: "Nine"
    }
    filtered = [x for x in arr if 1 <= x <= 9]
    filtered.sort()
    filtered.reverse()
    return [names[x] for x in filtered]

def order_by_points(nums):
    def digit_sum(n):
        s = str(n)
        if s.startswith('-'):
            digits = [int(d) for d in s[1:]]
            digits[0] = -digits[0]
            return sum(digits)
        else:
            return sum(int(d) for d in s)

    return sorted(nums, key=digit_sum)

def tri(n):
    if n == 0:
        return [1]

    result = [1, 3]

    for i in range(2, n + 1):
        if i % 2 == 0:
            result.append(1 + i // 2)
        else:
            # tri(i) = tri(i-1) + tri(i-2) + tri(i+1)
            # since i is odd, i+1 is even, so tri(i+1) = 1 + (i+1)//2
            tri_next = 1 + (i + 1) // 2
            result.append(result[i - 1] + result[i - 2] + tri_next)

    return result

def sort_array(array):
    if not array:
        return []
    total = array[0] + array[-1]
    sorted_copy = sorted(array, reverse=(total % 2 == 0))
    return sorted_copy

def compare_one(a, b):
    def to_float(x):
        if isinstance(x, str):
            return float(x.replace(',', '.'))
        return float(x)

    fa = to_float(a)
    fb = to_float(b)

    if fa == fb:
        return None
    elif fa > fb:
        return a
    else:
        return b
